"""
Task T014b: Calculate and log the percentage of valid records vs total raw input records.
Output: data/processed/validity_metrics.json
"""
import os
import json
import logging
import pandas as pd
from pathlib import Path
from typing import Dict, Any

from config import get_config, ensure_dirs
from utils import setup_logging, log_info, log_warning, log_error
from ingestion import load_dataset

def load_exclusion_log() -> Dict[str, Any]:
    """Load the exclusion log generated by T012."""
    config = get_config()
    exclusion_path = Path(config["data"]["processed"]) / "exclusion_log.json"
    if not exclusion_path.exists():
        log_error(f"Exclusion log not found at {exclusion_path}. Ensure T012 has run.")
        return {"total_excluded": 0, "counts": {}}
    
    with open(exclusion_path, "r") as f:
        return json.load(f)

def load_raw_count() -> int:
    """
    Determine the total number of raw input records.
    Strategy:
    1. Try to read a 'metadata.json' in data/raw/ that might contain 'total_records'.
    2. If not found, attempt to load the raw dataset file and count rows.
    3. If neither works, return 0 (will trigger a warning).
    """
    config = get_config()
    raw_dir = Path(config["data"]["raw"])
    metadata_path = raw_dir / "metadata.json"
    
    # Strategy 1: Check metadata file
    if metadata_path.exists():
        with open(metadata_path, "r") as f:
            meta = json.load(f)
            if "total_records" in meta:
                log_info(f"Found total_records in metadata.json: {meta['total_records']}")
                return meta["total_records"]
    
    # Strategy 2: Try to infer from the main dataset file if it exists and is small enough
    # We look for common extensions. We assume the dataset was loaded by T010/T011.
    # Since T010/T011 might have deleted or moved the raw file, we check for common names.
    possible_files = ["dataset.csv", "data.csv", "raw_data.csv", "wcst_data.csv"]
    for fname in possible_files:
        fpath = raw_dir / fname
        if fpath.exists():
            try:
                # Load only the index to count
                df = pd.read_csv(fpath, nrows=0)
                count = len(df)
                log_info(f"Estimated raw count from {fname}: {count}")
                return count
            except Exception as e:
                log_warning(f"Could not read {fname} for count: {e}")
    
    # Strategy 3: If we have a cleaned dataset, we can't easily know the raw count
    # without the exclusion log's total. We rely on the exclusion log logic.
    # However, the exclusion log T012 produces counts of EXCLUDED records.
    # If T012 is robust, it should have recorded the total raw count or we can derive it:
    # Total = Valid + Excluded.
    # But T012 might not have stored 'total_raw' explicitly if it just iterated and counted.
    # Let's check the exclusion log structure expected from T012.
    # If T012 wrote 'total_raw', we use it. If not, we must rely on file reading above.
    
    log_warning("Could not determine raw record count from metadata or file scan.")
    return 0

def calculate_validity_metrics() -> Dict[str, Any]:
    """
    Calculate validity metrics:
    - total_raw_records
    - valid_records_count
    - excluded_records_count
    - validity_percentage
    - exclusion_breakdown
    """
    config = get_config()
    ensure_dirs(config)
    
    # Load exclusion log
    exclusion_data = load_exclusion_log()
    excluded_count = exclusion_data.get("total_excluded", 0)
    exclusion_breakdown = exclusion_data.get("counts", {})
    
    # Load raw count
    total_raw = load_raw_count()
    
    # If we couldn't get raw count from file/metadata, try to infer from exclusion log
    # Some implementations might store 'total_processed' or similar in exclusion log.
    if total_raw == 0 and "total_raw" in exclusion_data:
        total_raw = exclusion_data["total_raw"]
    
    if total_raw == 0:
        log_error("Cannot calculate validity metrics: Total raw record count is 0 or unknown.")
        # Return a structure indicating failure or unknown status
        return {
            "status": "unknown",
            "total_raw_records": 0,
            "valid_records_count": 0,
            "excluded_records_count": excluded_count,
            "validity_percentage": 0.0,
            "message": "Could not determine total raw records. Check data/raw/ for metadata.json or raw CSV."
        }
    
    # Valid records = Total - Excluded
    # Note: T012 should have counted valid records implicitly by excluding invalid ones.
    # If T012 logic was: total - excluded = valid, we can derive it.
    valid_count = total_raw - excluded_count
    
    if valid_count < 0:
        log_error(f"Invalid state: Excluded ({excluded_count}) > Total ({total_raw}). Data corruption?")
        valid_count = 0
    
    validity_pct = (valid_count / total_raw) * 100 if total_raw > 0 else 0.0
    
    metrics = {
        "total_raw_records": total_raw,
        "valid_records_count": valid_count,
        "excluded_records_count": excluded_count,
        "validity_percentage": round(validity_pct, 2),
        "exclusion_breakdown": exclusion_breakdown,
        "status": "success"
    }
    
    return metrics

def main():
    """Main entry point for T014b."""
    setup_logging()
    log_info("Starting T014b: Validity Metrics Calculation")
    
    metrics = calculate_validity_metrics()
    
    config = get_config()
    output_path = Path(config["data"]["processed"]) / "validity_metrics.json"
    
    with open(output_path, "w") as f:
        json.dump(metrics, f, indent=2)
    
    log_info(f"Validity metrics written to {output_path}")
    log_info(f"Total Raw: {metrics['total_raw_records']}, Valid: {metrics['valid_records_count']}, Percentage: {metrics['validity_percentage']}%")
    
    return metrics

if __name__ == "__main__":
    main()
